from openai import OpenAI

client = OpenAI()

def monitor_thread_bloat(thread_id: str) -> dict:
    messages = client.beta.threads.messages.list(thread_id)

    file_token_estimate = 0
    user_token_estimate = 0

    for msg in messages.data:
        if msg.role == 'user':
            user_token_estimate += len(msg.content[0].text.value) // 4
        elif msg.annotations:
            file_citations = [ann for ann in msg.annotations if ann.type == 'file_citation']
            file_token_estimate += len(file_citations) * 2000  # Conservative estimate

    bloat_ratio = file_token_estimate / max(user_token_estimate, 1)

    return {
        'file_tokens_pct': file_token_estimate / (file_token_estimate + user_token_estimate),
        'bloat_ratio': bloat_ratio,
        'alert': bloat_ratio > 3.0
    }

