def rewrite_rag_query(user_query: str, metadata_filters: dict) -> str:
    filters = []
    if metadata_filters.get('category'):
        filters.append(f"category:{metadata_filters['category']}")
    if metadata_filters.get('date_after'):
        filters.append(f"date_after:{metadata_filters['date_after']}")

    filter_str = " " + " ".join(filters) if filters else ""
    return f"{user_query}{filter_str}"

