import vex

from openai import OpenAI

# Install: pip install openai vex-sdk

@vex.check(name="rag_retrieval_quality", severity="high")
def verify_rag_quality(run: dict, client: OpenAI) -> dict:
    thread_id = run['thread_id']

    # Get latest assistant message
    messages = client.beta.threads.messages.list(thread_id)
    msg = messages.data[0]

    if not msg.annotations:
        return {'pass': False, 'reason': 'No file citations found'}

    # Extract query context
    query = next((m.content[0].text.value for m in messages.data[1:] 
                  if m.role == 'user'), '')

    # Run relevance check
    relevance = check_retrieval_relevance(thread_id, query)
    coverage = analyze_citation_coverage(msg.content[0].text.value, [])

    if relevance['threshold_met'] and coverage['healthy']:
        return {'pass': True}

    return {
        'pass': False,
        'metrics': {
            'relevance_score': relevance['relevance_score'],
            'coverage_ratio': coverage['coverage_ratio']
        },
        'fix': 'Rewrite query with metadata filters or reduce max_results'
    }

# Deploy as webhook
vex.deploy_webhook(
    'openai-assistants-rag-quality',
    'https://api.openai.com/v1/threads/{thread_id}/runs/{run_id}',
    verify_rag_quality
)
